import { useState, useEffect } from "react";
import axios from "axios";
const API = "http://localhost:8001";
export default function App() {
  const [url, setUrl] = useState("");
  const [message, setMessage] = useState("");
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [recentScans, setRecentScans] = useState([]);
  useEffect(() => { fetchRecent(); }, []);
  const fetchRecent = async () => {
    try {
      const res = await axios.get(`${API}/recent-scans`);
      setRecentScans(res.data.scans || []);
    } catch (e) {}
  };
  const scan = async () => {
    if (!url) return;
    setLoading(true);
    setResult(null);
    try {
      const res = await axios.post(`${API}/scan`, { url, message });
      setResult(res.data);
      fetchRecent();
    } catch (e) { alert("Backend not running!"); }
    setLoading(false);
  };
  const getColor = (score) => {
    if (score >= 75) return "#ff4444";
    if (score >= 50) return "#ff8800";
    if (score >= 30) return "#ffcc00";
    return "#00c853";
  };
  const signals = result?.signals ? [
    { name: "AI Analysis", score: result.signals.ai_analysis?.ai_score || 0, max: 100, icon: "🧠", desc: result.signals.ai_analysis?.explanation || "" },
    { name: "Ghost Sandbox", score: result.signals.sandbox?.score || 0, max: 25, icon: "👻", desc: result.signals.sandbox?.verdict || "" },
    { name: "Click Velocity", score: result.signals.click_velocity?.score || 0, max: 20, icon: "⚡", desc: result.signals.click_velocity?.verdict || "" },
    { name: "Geo Velocity", score: result.signals.geo_velocity?.score || 0, max: 15, icon: "🌍", desc: result.signals.geo_velocity?.verdict || "" },
    { name: "Dwell Time", score: result.signals.dwell_time?.score || 0, max: 10, icon: "⏱️", desc: result.signals.dwell_time?.verdict || "" },
    { name: "VirusTotal", score: Math.min((result.signals.virustotal?.malicious_engines || 0) * 15, 40), max: 40, icon: "🔬", desc: `${result.signals.virustotal?.malicious_engines || 0} malicious engines out of ${result.signals.virustotal?.total_engines || 0} — ${result.signals.virustotal?.verdict || "UNKNOWN"}` },
  ] : [];
  return (
    <div style={{ minHeight: "100vh", background: "linear-gradient(135deg, #0f0c29, #302b63, #24243e)", color: "white", fontFamily: "'Segoe UI', sans-serif" }}>
      <div style={{ textAlign: "center", padding: "40px 20px 20px" }}>
        <div style={{ fontSize: "3rem" }}>🛡️</div>
        <h1 style={{ fontSize: "2.5rem", margin: "10px 0 5px", background: "linear-gradient(90deg, #a78bfa, #60a5fa)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>ShieldNetX</h1>
        <p style={{ color: "#94a3b8", margin: 0 }}>Cyber Threat Intelligence Platform</p>
      </div>
      {/* STATS BAR */}
      <div style={{ display: "flex", justifyContent: "center", gap: "30px", padding: "10px 20px 20px", flexWrap: "wrap" }}>
        {[["1,247", "URLs Scanned", "#f87171"], ["983", "Threats Blocked", "#fb923c"], ["298,450", "Indians Protected", "#4ade80"], ["95", "Engines Active", "#60a5fa"]].map(([val, label, color]) => (
          <div key={label} style={{ textAlign: "center", background: "rgba(255,255,255,0.05)", padding: "12px 24px", borderRadius: "12px", border: "1px solid rgba(255,255,255,0.1)" }}>
            <div style={{ fontSize: "1.5rem", fontWeight: "bold", color }}>{val}</div>
            <div style={{ fontSize: "0.7rem", color: "#94a3b8" }}>{label}</div>
          </div>
        ))}
      </div>
      {/* SCAN BOX */}
      <div style={{ maxWidth: "680px", margin: "0 auto", padding: "0 20px" }}>
        <div style={{ background: "rgba(255,255,255,0.05)", borderRadius: "16px", padding: "24px", border: "1px solid rgba(255,255,255,0.1)" }}>
          <h3 style={{ margin: "0 0 16px", color: "#a78bfa" }}>🔍 Scan a Link</h3>
          <input value={url} onChange={e => setUrl(e.target.value)} placeholder="Paste URL here..." style={{ width: "100%", padding: "12px", background: "rgba(255,255,255,0.1)", border: "1px solid rgba(255,255,255,0.2)", color: "white", borderRadius: "8px", fontSize: "1rem", marginBottom: "10px", boxSizing: "border-box" }} />
          <textarea value={message} onChange={e => setMessage(e.target.value)} placeholder="Paste the full WhatsApp/SMS message here (optional but improves accuracy)..." style={{ width: "100%", padding: "12px", background: "rgba(255,255,255,0.1)", border: "1px solid rgba(255,255,255,0.2)", color: "white", borderRadius: "8px", fontSize: "0.9rem", marginBottom: "10px", boxSizing: "border-box", minHeight: "80px", resize: "vertical" }} />
          <button onClick={scan} disabled={loading} style={{ width: "100%", padding: "14px", background: loading ? "#4c1d95" : "linear-gradient(90deg, #7c3aed, #4f46e5)", color: "white", border: "none", borderRadius: "8px", fontSize: "1rem", cursor: "pointer", fontWeight: "bold" }}>
            {loading ? "⏳ Scanning..." : "🔍 Scan Now"}
          </button>
        </div>
      </div>
      {/* RESULT */}
      {result && (
        <div style={{ maxWidth: "680px", margin: "20px auto", padding: "0 20px" }}>
          <div style={{ background: "rgba(255,255,255,0.05)", borderRadius: "16px", padding: "24px", border: `2px solid ${getColor(result.threat_score)}`, textAlign: "center", marginBottom: "16px" }}>
            <div style={{ fontSize: "4rem", fontWeight: "bold", color: getColor(result.threat_score) }}>{result.threat_score}</div>
            <div style={{ color: "#94a3b8", fontSize: "0.85rem" }}>THREAT SCORE OUT OF 100</div>
            <div style={{ display: "inline-block", marginTop: "8px", padding: "4px 20px", borderRadius: "20px", background: getColor(result.threat_score), color: "white", fontWeight: "bold" }}>{result.threat_level}</div>
            <div style={{ marginTop: "10px", color: "#94a3b8", fontSize: "0.85rem" }}>{result.signals?.ai_analysis?.explanation}</div>
            <div style={{ marginTop: "6px", color: "#a78bfa", fontSize: "0.85rem" }}>{result.signals?.ai_analysis?.tamil_explanation}</div>
          </div>
          {/* SIGNALS */}
          <div style={{ background: "rgba(255,255,255,0.05)", borderRadius: "16px", padding: "20px", border: "1px solid rgba(255,255,255,0.1)" }}>
            <h4 style={{ margin: "0 0 16px", color: "#a78bfa" }}>📊 Signal Breakdown</h4>
            {signals.map((sig, i) => (
              <div key={i} style={{ marginBottom: "14px" }}>
                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "4px" }}>
                  <span style={{ fontSize: "0.9rem" }}>{sig.icon} {sig.name}</span>
                  <span style={{ color: getColor((sig.score / sig.max) * 100), fontSize: "0.9rem" }}>{sig.score}/{sig.max}</span>
                </div>
                <div style={{ background: "rgba(255,255,255,0.1)", borderRadius: "4px", height: "6px" }}>
                  <div style={{ width: `${Math.min((sig.score / sig.max) * 100, 100)}%`, background: getColor((sig.score / sig.max) * 100), height: "6px", borderRadius: "4px", transition: "width 0.5s" }} />
                </div>
                <div style={{ color: "#64748b", fontSize: "0.75rem", marginTop: "2px" }}>{sig.desc}</div>
              </div>
            ))}
          </div>
        </div>
      )}
      {/* RECENT SCANS */}
      {recentScans.length > 0 && (
        <div style={{ maxWidth: "680px", margin: "20px auto", padding: "0 20px 40px" }}>
          <div style={{ background: "rgba(255,255,255,0.05)", borderRadius: "16px", padding: "20px", border: "1px solid rgba(255,255,255,0.1)" }}>
            <h4 style={{ margin: "0 0 16px", color: "#a78bfa" }}>🕐 Recent Scans</h4>
            {recentScans.slice(0, 5).map((scan, i) => (
              <div key={i} style={{ display: "flex", justifyContent: "space-between", padding: "8px 0", borderBottom: "1px solid rgba(255,255,255,0.05)" }}>
                <span style={{ color: "#94a3b8", fontSize: "0.85rem" }}>{scan.url?.substring(0, 45)}...</span>
                <span style={{ color: getColor(scan.threat_score || 0), fontWeight: "bold", fontSize: "0.85rem" }}>{scan.threat_score || "?"}/100</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
